const MICRON_DB = {"8": ["JWA60", "JW687"], "16": ["JW788"], "32": ["JZ132"], "64": ["JZ023", "JZ160", "JZ495", "JZ075", "JZ178", "JZ196", "JZ528"], "128": ["JZ057", "JZ144", "JZ156", "JZ064", "JZ380", "JZ341", "JZ417", "JZ447", "JZ413"], "256": ["JZ067", "JZ161", "JZ369", "JZ418", "JZ449", "JZ348", "JZ242", "JZ459"], "512": ["JZ347"]};

// ===== دالة البحث في البيانات =====
function searchInDB(code) {
  if (!code) return null;
  const codeUpper = code.toUpperCase().trim();
  
  // 1. Search NORMAL_DB
  for (const [capacity, codes] of Object.entries(NORMAL_DB)) {
    for (const c of codes) {
      if (codeUpper === c.toUpperCase() || codeUpper.startsWith(c.toUpperCase().split('-')[0])) {
        return { capacity, type: 'normal', storage: capacity.split('+')[0] };
      }
    }
  }
  
  // 2. Search EMMC_DB
  for (const [size, codes] of Object.entries(EMMC_DB)) {
    for (const c of codes) {
      if (codeUpper === c.toUpperCase() || codeUpper.includes(c.toUpperCase())) {
        return { storage: size, type: 'glass' };
      }
    }
  }
  
  // 3. Search MICRON_DB
  for (const [size, codes] of Object.entries(MICRON_DB)) {
    for (const c of codes) {
      if (codeUpper === c.toUpperCase()) {
        return { storage: size, type: 'glass' };
      }
    }
  }

  // 4. Shortcuts
  if (codeUpper.startsWith('KM')) {
    const kmkNum = codeUpper.match(/KMK(\d)X/);
    if (kmkNum) {
      if (kmkNum[1] === '7') return { storage: '8', type: 'normal' };
      if (kmkNum[1] === '8') return { storage: '16', type: 'normal' };
    }
    const samsungMap = {'N':'8','E':'16','X':'32','D':'32','C':'64','H':'64','P':'64','G':'128','V':'128','F':'256','S':'256'};
    const m = codeUpper.match(/([NEXDCHPGVFS])(000|100|200|600|700|800|900)/);
    if (m && samsungMap[m[1]]) return { storage: samsungMap[m[1]], type: 'normal' };
  }
  
  if (codeUpper.startsWith('H9')) {
    const hynixMap = {'17':'16','18':'16','19':'16','Q31':'16','Q82':'16','F31':'16','F82':'16','R31':'16','26':'32','27':'32','52':'64','53':'64','16':'128'};
    const num = codeUpper.substring(4, 6);
    if (hynixMap[num]) return { storage: hynixMap[num], type: 'normal' };
  }
  
  if (codeUpper.startsWith('SDIN')) {
    const m = codeUpper.match(/(16G|32G|64G|128G|256G|512G)/);
    if (m) return { storage: m[1].replace('G',''), type: 'normal' };
  }
  
  if (codeUpper.startsWith('KLM') || codeUpper.startsWith('KLU')) {
    const emmcMap = {'AG':'16','BG':'32','CG':'64','DG':'128','EG':'256','FG':'512'};
    for (const [k,v] of Object.entries(emmcMap)) {
      if (codeUpper.includes(k)) return { storage: v, type: 'glass' };
    }
  }
  
  if (codeUpper.startsWith('THG') || codeUpper.startsWith('THGB') || codeUpper.startsWith('THGA')) {
    const toshibaMap = {'G7':'16','G8':'32','G9':'64','T0':'128','T1':'256','T2':'512'};
    for (const [k,v] of Object.entries(toshibaMap)) {
      if (codeUpper.includes(k)) return { storage: v, type: 'glass' };
    }
  }
  
  if (codeUpper.startsWith('H26') || codeUpper.startsWith('H28')) {
    const hynixEmmcMap = {'54':'16','64':'32','74':'64','88':'128','9':'256'};
    const m = codeUpper.match(/H2[68][A-Z]?(\d+)/);
    if (m) {
      const num = m[1].substring(0,2);
      const num1 = m[1].substring(0,1);
      if (hynixEmmcMap[num]) return { storage: hynixEmmcMap[num], type: 'glass' };
      if (hynixEmmcMap[num1]) return { storage: hynixEmmcMap[num1], type: 'glass' };
    }
  }
  
  if (codeUpper.endsWith('05G')) return { storage: '32', type: 'glass' };
  if (codeUpper.endsWith('06G')) return { storage: '64', type: 'glass' };
  if (codeUpper.endsWith('07G')) return { storage: '128', type: 'glass' };
  
  if (codeUpper.startsWith('YMEC') && codeUpper.length >= 5) {
    const ymecMap = {'6':'32','7':'64','8':'128','9':'256'};
    const ymecNum = codeUpper[4];
    if (ymecMap[ymecNum]) return { storage: ymecMap[ymecNum], type: 'glass' };
  }
  
  return null;
}

app.post('/api/analyze', async (req, res) => {
    try {
        const { imageBase64 } = req.body;
        if (!imageBase64) return res.status(400).json({ error: "No image provided" });

        const model = genAI.getGenerativeModel({ model: "gemini-2.5-flash" });

        const prompt = `Identify the Memory IC on the mobile phone board first and completely ignore any CPU, GPU, Qualcomm, Snapdragon, or Mediatek chips, then if the image is upside down or mirrored mentally rotate it until the text is upright and readable, then read the engraved code on the Memory IC line by line while strictly reading characters exactly as they appear without guessing or completing any unclear parts and only return what is actually visible, then determine the company from the beginning of the code and apply the correct rule below to select the required part:
Samsung (KM): read the third line only
Samsung (KLM / KLU): read the first line only
SK Hynix (H9): read the full code
SK Hynix (H26 / H28 / HN8): read the full code
SanDisk (SDIN): read the second line only
Toshiba (THG): read the third line only
Kingston: read the left part of the fourth line only
Micron (JW / JZ): read the full code
YMTC (YMEC): read the bottom-left last line only
After reading the code, search the databases (NORMAL_DB, EMMC_DB, MICRON_DB) and shortcuts to find the storage size and type. Then return only this JSON with no extra text {"code":"EXACT_CODE","company":"COMPANY_NAME"} and if the code is not readable return {"code":"","company":""}`;

        const result = await model.generateContent({
            contents: [
                // Example 1: Samsung KM (عادي)
                { role: "user", parts: [
                    { inlineData: { data: EXAMPLE_KM, mimeType: "image/jpeg" } },
                    { text: "This is a Samsung KM (normal/عادي) memory IC. Read line 3 only." }
                ]},
                { role: "model", parts: [{ text: '{"code":"KM8L9001JM","company":"Samsung"}' }]},
                // Example 2: SK Hynix H9 (عادي)
                { role: "user", parts: [
                    { inlineData: { data: EXAMPLE_H9, mimeType: "image/jpeg" } },
                    { text: "This is a SK Hynix H9 (normal/عادي) memory IC. Read the full code." }
                ]},
                { role: "model", parts: [{ text: '{"code":"H9TQ17ADFTMC","company":"SK Hynix"}' }]},
                // Example 3: Samsung KLM (زجاجي)
                { role: "user", parts: [
                    { inlineData: { data: EXAMPLE_KLM, mimeType: "image/jpeg" } },
                    { text: "This is a Samsung KLM (glass/زجاجي) memory IC. Read line 1 only." }
                ]},
                { role: "model", parts: [{ text: '{"code":"KLUDG4UIEA","company":"Samsung"}' }]},
                // Actual image to analyze
                { role: "user", parts: [
                    { inlineData: { data: imageBase64, mimeType: "image/jpeg" } },
                    { text: prompt }
                ]}
            ],
            generationConfig: {
                temperature: 0.1,
                topP: 0.95,
                responseMimeType: "application/json"
            }
        });

        // Streaming - send characters as they come
        const response = await result.response;
        let text = response.text();
        text = text.replace(/```json/g, '').replace(/```/g, '').trim();

        let parsed;
        try {
            const jsonMatch = text.match(/\{[^{}]*"code"[^{}]*\}/);
            parsed = jsonMatch ? JSON.parse(jsonMatch[0]) : JSON.parse(text);
        } catch(e) {
            parsed = { code: '', company: '' };
        }

        // Search in databases
        const found = searchInDB(parsed.code);
        if (found) {
            parsed.storage = found.storage;
            parsed.type = found.type;
            parsed.capacity = found.capacity || '';
        }
        res.json(parsed);
    } catch (error) {
        console.error("Gemini Error:", error);
        res.status(500).json({ error: error.message });
    }
});

app.get('*', (req, res) => {
    res.sendFile(path.join(__dirname, 'public', 'index.html'));
});

app.listen(PORT, '0.0.0.0', () => {
    console.log(`Server is running on port ${PORT}`);
});
